        if (n % 2 == 0) return 2;
        long x = 2, y = 2, c = 1, d = 1;
        while (d == 1) {
            x = (x * x + c) % n;
            y = (y * y + c) % n;
            y = (y * y + c) % n;
            d = Gcd(Math.Abs(x - y), n);
        }
        return d != n ? d : n;
    }

